// api/share.js — handles both group roster and individual one-pager shares
const crypto = require('crypto');
const PDFDocument = require('pdfkit');

const TOKEN = process.env.BLOB_READ_WRITE_TOKEN;
const APP_URL = (process.env.NEXT_PUBLIC_APP_URL || process.env.APP_URL || 'https://milk-and-honey-music.vercel.app').replace(/\/$/, '');
const BLOB_API = 'https://blob.vercel-storage.com';

// ── Roster PDF generation (merged here, not a standalone file, to stay
// under Vercel Hobby's 12-serverless-function-per-deployment cap) ──────────
const MH_LOGO_BUF = Buffer.from('', 'base64');

const PDF_COLS = 3, PDF_ROWS = 5;
const PDF_PER_PAGE = PDF_COLS * PDF_ROWS;
const PDF_PAGE_W = 612, PDF_PAGE_H = 792; // US Letter, in PDF points
const PDF_MARGIN = 32;
const PDF_CONTENT_W = PDF_PAGE_W - PDF_MARGIN * 2;
const PDF_CONTENT_H = PDF_PAGE_H - PDF_MARGIN * 2;
const PDF_HEADER_H = 42;
const PDF_HEADER_GAP = 10;
const PDF_GAP = 9;
const PDF_GRID_H = PDF_CONTENT_H - PDF_HEADER_H - PDF_HEADER_GAP;
const PDF_CARD_H = Math.floor((PDF_GRID_H - (PDF_ROWS - 1) * PDF_GAP) / PDF_ROWS);
const PDF_CARD_W = Math.floor((PDF_CONTENT_W - (PDF_COLS - 1) * PDF_GAP) / PDF_COLS);

const PDF_BG = '#080809', PDF_SURFACE = '#111113', PDF_BORDER = '#1e1e22';
const PDF_TEXT = '#f4f4f5', PDF_TEXT2 = '#b4b4be', PDF_TEXT3 = '#8a8a98';
const PDF_GREEN = '#3eaa78';

function pdfInitials(name) {
  return (name || '').split(' ').filter(Boolean).slice(0, 2).map(w => w[0].toUpperCase()).join('');
}

async function pdfFetchImageBuffer(url) {
  if (!url) return null;
  try {
    const r = await fetch(url, { signal: AbortSignal.timeout(5000) });
    if (!r.ok) return null;
    return Buffer.from(await r.arrayBuffer());
  } catch { return null; }
}

function cardFields(c) {
  const types = (c.types || []).join(' · ');
  const team = c.label || c.pro || '';
  return { photoUrl: c.photoUrl, logoUrl: c.logoUrl, line1: types, line2: team };
}
function pdfDrawHeader(doc, title, count, isFirst) {
  doc.image(MH_LOGO_BUF, PDF_MARGIN, PDF_MARGIN + 8, { fit: [60, 26], align: 'left', valign: 'top' });
  doc.fillColor(PDF_TEXT).font('Helvetica-Bold').fontSize(15).text(title, PDF_MARGIN + 70, PDF_MARGIN + 12, { width: PDF_CONTENT_W - 70 - 90, height: 18, ellipsis: true });
  if (isFirst) {
    doc.fillColor(PDF_TEXT3).font('Helvetica').fontSize(10);
    const countText = `${count} client${count !== 1 ? 's' : ''}`;
    const w = doc.widthOfString(countText);
    doc.text(countText, PDF_MARGIN + PDF_CONTENT_W - w, PDF_MARGIN + 15, { lineBreak: false });
  }
  doc.moveTo(PDF_MARGIN, PDF_MARGIN + PDF_HEADER_H).lineTo(PDF_MARGIN + PDF_CONTENT_W, PDF_MARGIN + PDF_HEADER_H).lineWidth(1.5).strokeColor(PDF_GREEN).stroke();
}

async function pdfPrefetchImages(items) {
  const urls = new Set();
  items.forEach(item => {
    const { photoUrl, logoUrl } = cardFields(item);
    if (photoUrl) urls.add(photoUrl);
    if (logoUrl) urls.add(logoUrl);
  });
  const cache = new Map();
  const list = Array.from(urls);
  const CHUNK = 20;
  for (let i = 0; i < list.length; i += CHUNK) {
    const chunk = list.slice(i, i + CHUNK);
    await Promise.all(chunk.map(async url => { cache.set(url, await pdfFetchImageBuffer(url)); }));
  }
  return cache;
}

function pdfDrawCard(doc, item, x, y, imageCache) {
  doc.roundedRect(x, y, PDF_CARD_W, PDF_CARD_H, 8).fillAndStroke(PDF_SURFACE, PDF_BORDER);

  const { photoUrl, logoUrl, line1, line2 } = cardFields(item);
  const pad = 12;
  const avR = 18;
  const avCx = x + pad + avR, avCy = y + pad + avR;

  const photoBuf = photoUrl ? imageCache.get(photoUrl) : null;
  if (photoBuf) {
    try {
      doc.save();
      doc.circle(avCx, avCy, avR).clip();
      doc.image(photoBuf, avCx - avR, avCy - avR, { fit: [avR * 2, avR * 2], align: 'center', valign: 'center' });
      doc.restore();
    } catch {
      doc.circle(avCx, avCy, avR).fillAndStroke('#18181b', PDF_BORDER);
      doc.fillColor(PDF_TEXT2).font('Helvetica-Bold').fontSize(11).text(pdfInitials(item.name), avCx - avR, avCy - 5, { width: avR * 2, align: 'center', lineBreak: false });
    }
  } else {
    doc.circle(avCx, avCy, avR).fillAndStroke('#18181b', PDF_BORDER);
    doc.fillColor(PDF_TEXT2).font('Helvetica-Bold').fontSize(11).text(pdfInitials(item.name), avCx - avR, avCy - 5, { width: avR * 2, align: 'center', lineBreak: false });
  }

  const logoBuf = logoUrl ? imageCache.get(logoUrl) : null;
  if (logoBuf) {
    const lr = 11;
    const lcx = x + PDF_CARD_W - pad - lr, lcy = y + pad + lr;
    try {
      doc.circle(lcx, lcy, lr).fill('#ffffff');
      doc.image(logoBuf, lcx - lr + 2, lcy - lr + 2, { fit: [lr * 2 - 4, lr * 2 - 4], align: 'center', valign: 'center' });
    } catch {}
  }

  const textX = x + pad;
  const textY = avCy + avR + 8;
  const textW = PDF_CARD_W - pad * 2;
  doc.fillColor(PDF_TEXT).font('Helvetica-Bold').fontSize(11).text(item.name || '', textX, textY, { width: textW, height: 13, ellipsis: true });

  let ny = textY + 14;
  if (line1) {
    doc.fillColor(PDF_TEXT2).font('Helvetica').fontSize(9).text(line1, textX, ny, { width: textW, height: 11, ellipsis: true });
    ny += 12;
  }
  if (line2) {
    doc.fillColor(PDF_TEXT3).font('Helvetica').fontSize(8).text(line2, textX, ny, { width: textW, height: 10, ellipsis: true });
  }
}

async function buildRosterPdf(items, title) {
  const doc = new PDFDocument({ size: 'LETTER', margin: 0, bufferPages: true });
  const chunks = [];
  doc.on('data', c => chunks.push(c));
  const done = new Promise(resolve => doc.on('end', resolve));

  const imageCache = await pdfPrefetchImages(items);

  const pages = [];
  for (let i = 0; i < items.length; i += PDF_PER_PAGE) pages.push(items.slice(i, i + PDF_PER_PAGE));
  if (pages.length === 0) pages.push([]);

  for (let p = 0; p < pages.length; p++) {
    if (p > 0) doc.addPage({ size: 'LETTER', margin: 0 });
    doc.rect(0, 0, PDF_PAGE_W, PDF_PAGE_H).fill(PDF_BG);
    pdfDrawHeader(doc, title, items.length, p === 0);

    const pageItems = pages[p];
    for (let i = 0; i < pageItems.length; i++) {
      const col = i % PDF_COLS, row = Math.floor(i / PDF_COLS);
      const cx = PDF_MARGIN + col * (PDF_CARD_W + PDF_GAP);
      const cy = PDF_MARGIN + PDF_HEADER_H + PDF_HEADER_GAP + row * (PDF_CARD_H + PDF_GAP);
      pdfDrawCard(doc, pageItems[i], cx, cy, imageCache);
    }
  }

  doc.end();
  await done;
  return Buffer.concat(chunks);
}

async function sendRosterPdf(data, res) {
  const items = data.athletes || [];
  const title = data.title || 'Milk & Honey Music — Client Roster';
  const pdf = await buildRosterPdf(items, title);
  const filename = title.replace(/[^a-z0-9]+/gi, '-').replace(/^-+|-+$/g, '') + '.pdf';
  res.setHeader('Content-Type', 'application/pdf');
  res.setHeader('Content-Disposition', `attachment; filename="${filename}"`);
  return res.send(pdf);
}

module.exports = async function handler(req, res) {
  res.setHeader('Access-Control-Allow-Origin', '*');
  res.setHeader('Access-Control-Allow-Methods', 'GET,POST,OPTIONS');
  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
  if (req.method === 'OPTIONS') return res.status(200).end();
  if (!TOKEN) return res.status(500).json({ error: 'BLOB_READ_WRITE_TOKEN not set' });

  // ── POST: save share ────────────────────────────────────────────────────────
  if (req.method === 'POST') {
    try {
      const body = req.body;
      if (!body) return res.status(400).json({ error: 'No data provided' });

      const id = crypto.randomBytes(8).toString('hex');
      const filename = `share-${id}.json`;

      let payload;
      if (body.type === 'individual') {
        if (!body.athlete?.name) return res.status(400).json({ error: 'No athlete provided' });
        payload = JSON.stringify({
          id,
          type: 'individual',
          createdAt: new Date().toISOString(),
          athlete:       body.athlete,
          brandName:     body.brandName     || '',
          keywords:      body.keywords      || [],
          pitch:         body.pitch         || '',
          ideas:         body.ideas         || [],
          aboutText:     body.aboutText     || '',
          secondaryPhoto: body.secondaryPhoto || null,
          brandLogo:     body.brandLogo     || null,
          theme:         body.theme         || 'dark',
          // Pitch mode + generic outreach
          pitchMode:     body.pitchMode     || 'specific',
          outreachTitle: body.outreachTitle || '',
          outreachCards: body.outreachCards || [],
          // Photo positioning
          photoX:        body.photoX        ?? 50,
          photoY:        body.photoY        ?? 50,
          photoZoom:     body.photoZoom     ?? 100,
          fontScale:     body.fontScale     ?? 1.0,
          // Section toggles
          toggles: {
            showSocials:   body.toggles?.showSocials   ?? true,
            showMusic:     body.toggles?.showMusic     ?? true,
            showInterests: body.toggles?.showInterests ?? true,
            showBrands:    body.toggles?.showBrands    ?? true,
            showPitch:     body.toggles?.showPitch     ?? true,
          },
        });
      } else if (body.type === 'roster-share') {
        // Interactive shareable roster
        const { athletes, title, expiresAt } = body;
        if (!athletes?.length) return res.status(400).json({ error: 'No athletes provided' });
        payload = JSON.stringify({
          id, type: 'roster-share',
          createdAt: new Date().toISOString(),
          expiresAt: expiresAt || null,
          title: title || 'Milk & Honey Sports — Athlete Roster',
          athletes,
        });
      } else {
        // Group roster
        const { athletes, title, showSocials, showReach, showStats, showClassOf, cardSize, theme } = body;
        if (!athletes?.length) return res.status(400).json({ error: 'No athletes provided' });
        payload = JSON.stringify({
          id, type: 'group', createdAt: new Date().toISOString(),
          title: title || 'Milk & Honey Sports — Athlete Roster',
          athletes, settings: { showSocials, showReach, showStats, showClassOf, cardSize, theme },
        });
      }

      const uploadResp = await fetch(`${BLOB_API}/${filename}`, {
        method: 'PUT',
        headers: { 'authorization': `Bearer ${TOKEN}`, 'x-api-version': '7', 'content-type': 'application/json' },
        body: payload,
      });

      const uploadText = await uploadResp.text();
      if (!uploadResp.ok) throw new Error(`Blob upload failed (${uploadResp.status}): ${uploadText}`);

      const url = body.type === 'roster-share'
        ? `${APP_URL}/roster/${id}`
        : `${APP_URL}/share/${id}`;
      return res.json({ id, url });
    } catch (err) {
      console.error('Share create error:', err.message);
      return res.status(500).json({ error: err.message });
    }
  }

  // ── GET: retrieve share ─────────────────────────────────────────────────────
  if (req.method === 'GET') {
    try {
      const { id } = req.query;
      if (!id) return res.status(400).json({ error: 'Missing id' });

      const listParams = new URLSearchParams({ prefix: `share-${id}`, limit: '1' });
      const listResp = await fetch(`${BLOB_API}?${listParams}`, {
        headers: { 'authorization': `Bearer ${TOKEN}`, 'x-api-version': '7' },
      });
      if (!listResp.ok) return res.status(404).json({ error: 'Share not found' });

      const listData = await listResp.json();
      const blob = listData.blobs?.[0];
      if (!blob) return res.status(404).json({ error: 'Share not found or expired' });

      const dataResp = await fetch(blob.url);
      if (!dataResp.ok) return res.status(404).json({ error: 'Share content unavailable' });

      let data;
      try { data = await dataResp.json(); }
      catch(e) { return res.status(500).json({ error: 'Failed to parse share data' }); }

      if (req.query.format === 'pdf') {
        try { return await sendRosterPdf(data, res); }
        catch (err) { console.error('Roster PDF error:', err); return res.status(500).send('Failed to generate PDF: ' + err.message); }
      }

      return res.json(data);
    } catch (err) {
      console.error('Share fetch error:', err.message);
      return res.status(500).json({ error: err.message });
    }
  }

  return res.status(405).json({ error: 'Method not allowed' });
};
